</header>

<script>
(function () {
    // Mobile nav toggle
    var toggle = document.getElementById('menu-toggle');
    var nav    = document.getElementById('primary-nav');
    if (toggle && nav) {
        toggle.addEventListener('click', function () {
            var expanded = toggle.getAttribute('aria-expanded') === 'true';
            toggle.setAttribute('aria-expanded', String(!expanded));
            nav.classList.toggle('is-open');
        });
    }

    // Nav starfield
    var container = document.getElementById('nav-stars');
    var header    = container && container.closest('.site-header');
    if (!container || !header) return;

    var w = header.offsetWidth;
    var h = header.offsetHeight;

    for (var i = 0; i < 60; i++) {
        var star = document.createElement('div');
        star.className = 'site-header__star';
        var size = Math.random() * 1.5 + 0.5;
        star.style.cssText = [
            'width:'         + size + 'px',
            'height:'        + size + 'px',
            'top:'           + (Math.random() * 100) + '%',
            'left:'          + (Math.random() * 100) + '%',
            '--duration:'    + (Math.random() * 4 + 3) + 's',
            '--delay:'       + (Math.random() * 8) + 's',
            '--max-opacity:' + (Math.random() * 0.5 + 0.15),
        ].join(';');
        container.appendChild(star);
    }
})();
</script>
